export const getSimulateRebalanceUrl = () => {




  return `/api/portfolio/rebalance`
}

/**
 * @summary Simulate a portfolio rebalance (does not place real trades)
 */
export const simulateRebalance = async (rebalanceRequest: RebalanceRequest, options?: RequestInit): Promise<RebalanceResponse> => {

  return customFetch<RebalanceResponse>(getSimulateRebalanceUrl(),
  {
    ...options,
    method: 'POST',
    headers: { 'Content-Type': 'application/json', ...options?.headers },
    body: JSON.stringify(rebalanceRequest)
  }
);}




export const getSimulateRebalanceMutationOptions = <TError = ErrorType<BadRequestResponse>,
    TContext = unknown>(options?: { mutation?:UseMutationOptions<Awaited<ReturnType<typeof simulateRebalance>>, TError,{data: BodyType<RebalanceRequest>}, TContext>, request?: SecondParameter<typeof customFetch>}
): UseMutationOptions<Awaited<ReturnType<typeof simulateRebalance>>, TError,{data: BodyType<RebalanceRequest>}, TContext> => {

const mutationKey = ['simulateRebalance'];
const {mutation: mutationOptions, request: requestOptions} = options ?
      options.mutation && 'mutationKey' in options.mutation && options.mutation.mutationKey ?
      options
      : {...options, mutation: {...options.mutation, mutationKey}}
      : {mutation: { mutationKey, }, request: undefined};




      const mutationFn: MutationFunction<Awaited<ReturnType<typeof simulateRebalance>>, {data: BodyType<RebalanceRequest>}> = (props) => {
          const {data} = props ?? {};

          return  simulateRebalance(data,requestOptions)
        }






  return  { mutationFn, ...mutationOptions }}

    export type SimulateRebalanceMutationResult = NonNullable<Awaited<ReturnType<typeof simulateRebalance>>>
    export type SimulateRebalanceMutationBody = BodyType<RebalanceRequest>
    export type SimulateRebalanceMutationError = ErrorType<BadRequestResponse>

    /**
 * @summary Simulate a portfolio rebalance (does not place real trades)
 */
export const useSimulateRebalance = <TError = ErrorType<BadRequestResponse>,
    TContext = unknown>(options?: { mutation?:UseMutationOptions<Awaited<ReturnType<typeof simulateRebalance>>, TError,{data: BodyType<RebalanceRequest>}, TContext>, request?: SecondParameter<typeof customFetch>}
 ): UseMutationResult<
        Awaited<ReturnType<typeof simulateRebalance>>,
        TError,
        {data: BodyType<RebalanceRequest>},
        TContext
      > => {
      return useMutation(getSimulateRebalanceMutationOptions(options));
    }

